  1→/**
  2→ * Speed ramping and time compression for recordings.
  3→ *
  4→ * Implements Cursor-style playback plan generation:
  5→ * - Action windows (clicks, typing, scrolling) play at 1x
  6→ * - Idle gaps between actions are compressed (up to 8x)
  7→ * - Leading/trailing dead time is trimmed
  8→ *
  9→ * The algorithm is adapted from Cursor's createPlaybackSegments()
 10→ * to work with our ffmpeg-based pipeline (no Rust renderer).
 11→ */
 12→
 13→import type { AgentEvent } from "../types.js";
 14→
 15→// ---------------------------------------------------------------------------
 16→// Types
 17→// ---------------------------------------------------------------------------
 18→
 19→export interface PlaybackSegment {
 20→  type: "action" | "gap";
 21→  sourceStartMs: number;
 22→  sourceEndMs: number;
 23→  sourceDurationMs: number;
 24→  outputStartMs: number;
 25→  outputEndMs: number;
 26→  outputDurationMs: number;
 27→  /** 1.0 = normal speed, 4.0 = 4x fast-forward */
 28→  playbackRate: number;
 29→}
 30→
 31→export interface PlaybackPlan {
 32→  segments: PlaybackSegment[];
 33→  outputDurationMs: number;
 34→  /** Leading dead time trimmed from source (ms before first action window). */
 35→  trimStartMs: number;
 36→}
 37→
 38→export interface SpeedRampConfig {
 39→  /** Time to show before each action at 1x (ms). */
 40→  preActionPaddingMs: number;
 41→  /** Time to show after each action at 1x (ms). */
 42→  postActionPaddingMs: number;
 43→  /** Target output duration for compressed gaps (ms). */
 44→  targetGapOutputMs: number;
 45→  /** Maximum output duration for any gap (ms). */
 46→  maxGapOutputMs: number;
 47→  /** Maximum playback rate for gap compression. */
 48→  maxPlaybackRate: number;
 49→  /** Minimum gap duration to trigger compression (ms). Shorter gaps stay at 1x. */
 50→  minGapToSpeedUp: number;
 51→}
 52→
 53→export const DEFAULT_SPEED_RAMP_CONFIG: SpeedRampConfig = {
 54→  preActionPaddingMs: 600,
 55→  postActionPaddingMs: 400,
 56→  targetGapOutputMs: 1200,
 57→  maxGapOutputMs: 2000,
 58→  maxPlaybackRate: 8,
 59→  minGapToSpeedUp: 800,
 60→};
 61→
 62→// ---------------------------------------------------------------------------
 63→// Event filtering
 64→// ---------------------------------------------------------------------------
 65→
 66→/** Actions that represent meaningful user/agent interaction. */
 67→export function isMeaningfulAction(event: AgentEvent): boolean {
 68→  switch (event.type) {
 69→    case "click":
 70→    case "type":
 71→    case "scroll":
 72→    case "navigate":
 73→    case "drag":
 74→      return true;
 75→    case "idle":
 76→    case "screenshot":
 77→      return false;
 78→    default:
 79→      return false;
 80→  }
 81→}
 82→
 83→// ---------------------------------------------------------------------------
 84→// Playback plan generation
 85→// ---------------------------------------------------------------------------
 86→
 87→interface ActionWindow {
 88→  start: number;
 89→  end: number;
 90→}
 91→
 92→/**
 93→ * Create a playback plan from agent events.
 94→ *
 95→ * Action windows play at 1x speed. Gaps between actions are compressed
 96→ * based on their duration. Leading dead time before the first action is trimmed.
 97→ */
 98→export function createPlaybackPlan(
 99→  events: AgentEvent[],
100→  sourceDurationMs: number,
101→  config?: Partial<SpeedRampConfig>
102→): PlaybackPlan {
103→  const cfg = { ...DEFAULT_SPEED_RAMP_CONFIG, ...config };
104→
105→  // Extract and sort meaningful action timestamps
106→  const timestamps = events
107→    .filter(isMeaningfulAction)
108→    .map((e) => e.t)
109→    .sort((a, b) => a - b);
110→
111→  // No actions — single segment at 1x
112→  if (timestamps.length === 0) {
113→    return {
114→      segments: [
115→        {
116→          type: "gap",
117→          sourceStartMs: 0,
118→          sourceEndMs: sourceDurationMs,
119→          sourceDurationMs: sourceDurationMs,
120→          outputStartMs: 0,
121→          outputEndMs: sourceDurationMs,
122→          outputDurationMs: sourceDurationMs,
123→          playbackRate: 1,
124→        },
125→      ],
126→      outputDurationMs: sourceDurationMs,
127→      trimStartMs: 0,
128→    };
129→  }
130→
131→  // Build action windows with padding, merged when overlapping
132→  const actionWindows: ActionWindow[] = [];
133→  for (const ts of timestamps) {
134→    const start = Math.max(0, ts - cfg.preActionPaddingMs);
135→    const end = Math.min(sourceDurationMs, ts + cfg.postActionPaddingMs);
136→
137→    if (actionWindows.length > 0) {
138→      const last = actionWindows[actionWindows.length - 1];
139→      if (start <= last.end) {
140→        last.end = Math.max(last.end, end);
141→        continue;
142→      }
143→    }
144→    actionWindows.push({ start, end });
145→  }
146→
147→  // Build segments
148→  const segments: PlaybackSegment[] = [];
149→  let outputTime = 0;
150→  let lastSourceEnd = 0;
151→
152→  const maxGap =
153→    Number.isFinite(cfg.maxGapOutputMs) && cfg.maxGapOutputMs > 0
154→      ? cfg.maxGapOutputMs
155→      : Number.POSITIVE_INFINITY;
156→
157→  for (const window of actionWindows) {
158→    // Gap before this action window
159→    if (window.start > lastSourceEnd) {
160→      const gap = buildGapSegment(lastSourceEnd, window.start, outputTime, cfg, maxGap);
161→      segments.push(gap);
162→      outputTime += gap.outputDurationMs;
163→    }
164→
165→    // Action window at 1x
166→    const actionDuration = window.end - window.start;
167→    segments.push({
168→      type: "action",
169→      sourceStartMs: window.start,
170→      sourceEndMs: window.end,
171→      sourceDurationMs: actionDuration,
172→      outputStartMs: outputTime,
173→      outputEndMs: outputTime + actionDuration,
174→      outputDurationMs: actionDuration,
175→      playbackRate: 1,
176→    });
177→    outputTime += actionDuration;
178→    lastSourceEnd = window.end;
179→  }
180→
181→  // Trailing gap after last action
182→  if (lastSourceEnd < sourceDurationMs) {
183→    const gap = buildGapSegment(lastSourceEnd, sourceDurationMs, outputTime, cfg, maxGap);
184→    segments.push(gap);
185→    outputTime += gap.outputDurationMs;
186→  }
187→
188→  // Compute trim: everything before first action - padding
189→  const trimStartMs = Math.max(0, timestamps[0] - cfg.preActionPaddingMs);
190→
191→  return {
192→    segments,
193→    outputDurationMs: outputTime,
194→    trimStartMs,
195→  };
196→}
197→
198→function buildGapSegment(
199→  sourceStart: number,
200→  sourceEnd: number,
201→  outputStart: number,
202→  cfg: SpeedRampConfig,
203→  maxGap: number
204→): PlaybackSegment {
205→  const gapSourceDuration = sourceEnd - sourceStart;
206→  let playbackRate = 1;
207→  let gapOutputDuration = gapSourceDuration;
208→
209→  if (gapSourceDuration > cfg.minGapToSpeedUp) {
210→    const idealRate = gapSourceDuration / cfg.targetGapOutputMs;
211→    const minRateForMaxWait = maxGap === Number.POSITIVE_INFINITY ? 0 : gapSourceDuration / maxGap;
212→    const effectiveMax = cfg.maxPlaybackRate;
213→    playbackRate = Math.min(idealRate, effectiveMax);
214→    gapOutputDuration = gapSourceDuration / playbackRate;
215→  }
216→
217→  return {
218→    type: "gap",
219→    sourceStartMs: sourceStart,
220→    sourceEndMs: sourceEnd,
221→    sourceDurationMs: gapSourceDuration,
222→    outputStartMs: outputStart,
223→    outputEndMs: outputStart + gapOutputDuration,
224→    outputDurationMs: gapOutputDuration,
225→    playbackRate,
226→  };
227→}
228→
229→// ---------------------------------------------------------------------------
230→// Time mapping
231→// ---------------------------------------------------------------------------
232→
233→/** Map a source timestamp to the corresponding output timestamp. */
