  1→import { randomBytes } from "node:crypto";
  2→import { unlink } from "node:fs/promises";
  3→import { tmpdir } from "node:os";
  4→import { join } from "node:path";
  5→import type { AgentEvent, AgentEventType } from "../types.js";
  6→import { CameraEngine } from "../camera/engine.js";
  7→import { TimelineRecorder } from "../recorder/encoder.js";
  8→import { FfmpegRecorder, detectFfmpeg, probeVideoDimensions } from "./ffmpeg-recorder.js";
  9→import { StreamRecorder } from "./stream-capture.js";
 10→import { mapTimelineToOutput } from "../recorder/render-plan.js";
 11→import { extractThumbnail } from "./thumbnail.js";
 12→import type {
 13→  Chapter,
 14→  RecordingResult,
 15→  RecordingSessionState,
 16→  RecordingStartParams,
 17→  RecordingStatus,
 18→  ResolvedRecordingConfig,
 19→} from "./types.js";
 20→
 21→/**
 22→ * Generate a short, readable session ID.
 23→ * Format: rec_{6 hex chars} (e.g. "rec_a1b2c3")
 24→ */
 25→function generateSessionId(): string {
 26→  return `rec_${randomBytes(3).toString("hex")}`;
 27→}
 28→
 29→/**
 30→ * Resolve user-provided params into a fully resolved config with defaults.
 31→ *
 32→ * Source size defaults to 1280x720 (agent-browser's default viewport).
 33→ * When using stream capture, the actual frame dimensions are auto-detected
 34→ * from the stream metadata and override this at post-processing time.
 35→ */
 36→function resolveConfig(params: RecordingStartParams): ResolvedRecordingConfig {
 37→  const timestamp = Date.now();
 38→  return {
 39→    outputPath: params.outputPath ?? join(tmpdir(), `recording-${timestamp}.mp4`),
 40→    sourceSize: {
 41→      width: params.sourceWidth ?? 1280,
 42→      height: params.sourceHeight ?? 720,
 43→    },
 44→    outputSize: {
 45→      width: params.outputWidth ?? 1920,
 46→      height: params.outputHeight ?? 1080,
 47→    },
 48→    fps: params.fps ?? 30,
 49→    deviceFrame: params.deviceFrame ?? "none",
 50→    background: params.background ?? { type: "gradient", colors: ["#0f0f23", "#1a1a3e"] },
 51→    captureMethod: params.captureMethod ?? "none",
 52→    display: params.display ?? ":99",
 53→  };
 54→}
 55→
 56→/**
 57→ * Internal per-session state.
 58→ */
 59→interface InternalSession {
 60→  state: RecordingSessionState;
 61→  engine: CameraEngine;
 62→  timelineRecorder: TimelineRecorder;
 63→  /** avfoundation / x11grab recorder (two-pass: capture then post-process) */
 64→  ffmpegRecorder: FfmpegRecorder;
 65→  rawCapturePath: string | null;
 66→  /** WebSocket stream recorder (agent-browser frame stream → ffmpeg) */
 67→  streamRecorder: StreamRecorder | null;
 68→}
 69→
 70→/**
 71→ * Manages multiple concurrent recording sessions.
 72→ *
 73→ * Capture backends:
 74→ *   - "stream": WebSocket stream from agent-browser, 10fps, no permission, no CDP conflicts
 75→ *   - "avfoundation": macOS native capture, 30fps, needs Screen Recording permission
 76→ *   - "x11grab": Linux Xvfb, 30fps
 77→ *   - "auto": try stream (if available), then avfoundation, fall back to none
 78→ *   - "none": events-only, no video capture
 79→ *
 80→ * All capture backends produce a raw MP4, which is then post-processed
 81→ * with camera effects (zoompan/crop filter) from the timeline.
 82→ */
 83→export class SessionManager {
 84→  private sessions = new Map<string, InternalSession>();
 85→  private ffmpegAvailable: boolean | null = null;
 86→
 87→  /**
 88→   * Create a new recording session.
 89→   */
 90→  async create(params: RecordingStartParams): Promise<string> {
 91→    const id = generateSessionId();
 92→    const config = resolveConfig(params);
 93→
 94→    const engine = new CameraEngine({ sourceSize: config.sourceSize });
 95→    const timelineRecorder = new TimelineRecorder({ fps: config.fps });
 96→    const ffmpegRecorder = new FfmpegRecorder();
 97→
 98→    const state: RecordingSessionState = {
 99→      id,
100→      status: "recording",
101→      config,
102→      events: [],
103→      chapters: [],
104→      startTime: Date.now(),
105→    };
106→
107→    let rawCapturePath: string | null = null;
108→    let streamRecorder: StreamRecorder | null = null;
109→
110→    // Resolve capture method
111→    let method = config.captureMethod;
112→    if (method === "auto") {
113→      method = await this.resolveAutoCapture();
114→    }
115→
116→    if (method === "stream") {
117→      // WebSocket stream from agent-browser — no OS permission, no CDP conflicts
118→      const streamPort = this.resolveStreamPort();
119→      if (streamPort) {
120→        rawCapturePath = join(tmpdir(), `raw-${id}.mp4`);
121→        streamRecorder = new StreamRecorder({
122→          outputPath: rawCapturePath,
123→        });
124→
125→        try {
126→          await streamRecorder.start(streamPort);
127→        } catch (err) {
128→          console.error(`[session-manager] Stream capture failed: ${err}`);
129→          streamRecorder = null;
130→          rawCapturePath = null;
131→          // Continue without capture — events still record
132→        }
133→      } else {
134→        console.error("[session-manager] No stream port found, falling back to events-only");
135→      }
136→    } else if (method === "avfoundation" || method === "x11grab") {
137→      // Native ffmpeg capture
138→      if (this.ffmpegAvailable === null) {
139→        this.ffmpegAvailable = (await detectFfmpeg()) !== null;
140→      }
141→      if (!this.ffmpegAvailable) {
142→        throw new Error("ffmpeg is not available. Install ffmpeg or use captureMethod: 'none'.");
143→      }
144→
145→      rawCapturePath = join(tmpdir(), `raw-${id}.mp4`);
146→
147→      try {
148→        await ffmpegRecorder.startCapture({
149→          method,
150→          sourceSize: config.sourceSize,
151→          fps: config.fps,
152→          display: config.display,
153→          outputPath: rawCapturePath,
154→        });
155→      } catch (err) {
156→        if (method === "avfoundation" && config.captureMethod === "auto") {
157→          // avfoundation failed (likely no Screen Recording permission).
158→          // Fall back to events-only.
159→          console.error(
160→            `[session-manager] avfoundation failed (grant Screen Recording permission in System Settings): ${err}`
161→          );
162→          rawCapturePath = null;
163→        } else {
164→          throw err;
165→        }
166→      }
167→    }
168→
169→    timelineRecorder.start();
170→
171→    this.sessions.set(id, {
172→      state,
173→      engine,
174→      timelineRecorder,
175→      ffmpegRecorder,
176→      rawCapturePath,
177→      streamRecorder,
178→    });
179→
180→    return id;
181→  }
182→
183→  /**
184→   * Push an agent event into a recording session.
185→   * Drives the camera engine's auto-zoom/pan behavior.
186→   */
187→  event(
188→    sessionId: string,
189→    type: AgentEventType,
190→    x: number,
191→    y: number,
192→    meta?: {
193→      elementRect?: { x: number; y: number; width: number; height: number };
194→      text?: string;
195→      url?: string;
196→      direction?: string;
197→    }
198→  ): number {
199→    const session = this.getSession(sessionId);
200→    if (session.state.status !== "recording") {
201→      throw new Error(`Session ${sessionId} is not recording (status: ${session.state.status})`);
202→    }
203→
204→    const t = Date.now() - session.state.startTime;
205→
206→    const eventMeta: Record<string, unknown> = {};
207→    if (meta?.text) eventMeta.text = meta.text;
208→    if (meta?.url) eventMeta.url = meta.url;
209→    if (meta?.direction) eventMeta.direction = meta.direction;
210→
211→    const agentEvent: AgentEvent = {
212→      type,
213→      t,
214→      x,
215→      y,
216→      elementRect: meta?.elementRect,
217→      meta: eventMeta,
218→    };
219→
220→    session.state.events.push(agentEvent);
221→    session.engine.pushEvent(agentEvent);
222→    session.engine.step(1 / session.state.config.fps);
223→
224→    const camera = session.engine.getTransform();
225→    const cursor = session.engine.getCursorState();
226→    session.timelineRecorder.captureFrame(t, camera, {
227→      x: cursor.x,
228→      y: cursor.y,
229→      clicking: cursor.clicking,
230→      visible: cursor.visible,
231→    });
232→
233→    return session.state.events.length - 1;
234→  }
235→
236→  /**
237→   * Add a chapter marker to the session.
238→   */
239→  chapter(sessionId: string, title: string): { chapterIndex: number; timestamp: number } {
240→    const session = this.getSession(sessionId);
241→    if (session.state.status !== "recording") {
242→      throw new Error(`Session ${sessionId} is not recording (status: ${session.state.status})`);
243→    }
244→
245→    const timestamp = Date.now() - session.state.startTime;
246→    const chapter: Chapter = {
247→      title,
248→      timestamp,
249→      eventIndex: session.state.events.length,
250→    };
251→
252→    session.state.chapters.push(chapter);
253→
254→    return {
255→      chapterIndex: session.state.chapters.length - 1,
256→      timestamp,
257→    };
258→  }
259→
260→  /**
261→   * Stop a recording session and produce the final MP4.
262→   *
263→   * Pipeline:
264→   *   1. Stop capture (stream or avfoundation/x11grab)
265→   *   2. Generate camera timeline from recorded events
266→   *   3. Apply zoompan/crop filter to raw capture → final MP4
267→   */
268→  async stop(
269→    sessionId: string,
270→    options?: { addWatermark?: boolean; watermarkText?: string }
271→  ): Promise<RecordingResult> {
272→    if (options?.addWatermark) {
273→      throw new Error("Watermarking is not yet supported by the current renderer.");
274→    }
275→
276→    const session = this.getSession(sessionId);
277→    if (session.state.status !== "recording") {
278→      throw new Error(`Session ${sessionId} is not recording (status: ${session.state.status})`);
279→    }
280→
281→    session.state.status = "processing";
282→    session.state.endTime = Date.now();
283→
284→    try {
285→      // Stop the event-driven timeline recorder (we'll regenerate a continuous
286→      // timeline below using processTimeline at the raw video's fps).
287→      session.timelineRecorder.stop();
288→      const config = session.state.config;
289→      const duration = (session.state.endTime! - session.state.startTime) / 1000;
290→      let videoProduced = false;
291→      let playbackPlan: import("../recorder/render-plan.js").PlaybackPlan | null = null;
292→
293→      // The raw video's fps: use measured delivery rate for stream, config for native.
294→      const _rawFps = session.streamRecorder
295→        ? (session.streamRecorder.actualFps ?? 10)
296→        : config.fps;
297→
298→      // --- Stop stream recorder ---
299→      let actualSourceSize = config.sourceSize;
300→      if (session.streamRecorder) {
301→        try {
302→          const rawPath = await session.streamRecorder.stop();
303→          if (rawPath) {
304→            session.rawCapturePath = rawPath;
305→          } else {
306→            // stop() returned null → 0 frames captured
307→            console.error(
308→              "[session-manager] Stream recorder captured 0 frames, skipping post-process"
309→            );
310→            session.rawCapturePath = null;
311→          }
312→        } catch (err) {
313→          console.error("[session-manager] Stream capture stop failed:", err);
314→          session.rawCapturePath = null;
315→        }
316→
317→        // Warn if frame count is too low for the session duration
318→        const expectedMin = Math.max(1, Math.floor(duration * 5));
319→        if (session.streamRecorder.frames > 0 && session.streamRecorder.frames < expectedMin) {
320→          console.error(
321→            `[session-manager] Low frame count: ${session.streamRecorder.frames} frames for ${duration.toFixed(1)}s ` +
322→              `(expected >= ${expectedMin}, dropped: ${session.streamRecorder.dropped})`
323→          );
324→        }
325→      }
326→
327→      // --- Stop avfoundation/x11grab recorder ---
328→      if (session.ffmpegRecorder.isCapturing()) {
329→        try {
330→          await session.ffmpegRecorder.stopCapture();
331→        } catch (err) {
332→          console.error("[session-manager] ffmpeg capture stop failed:", err);
333→          session.rawCapturePath = null;
334→          if (session.state.events.length === 0) throw err;
335→        }
336→      }
337→
338→      // --- Detect actual raw video dimensions via ffprobe ---
339→      if (session.rawCapturePath) {
340→        const probed = await probeVideoDimensions(session.rawCapturePath);
341→        if (probed) {
342→          actualSourceSize = probed;
343→          console.error(`[session-manager] Probed raw video: ${probed.width}x${probed.height}`);
