  1→/**
  2→ * Recording Tool Renderers
  3→ *
  4→ * - recording_start → minimal status row
  5→ * - recording_stop → prominent video card in chat, click opens modal player
  6→ */
  7→
  8→import { useState, useEffect, useRef, useCallback } from "react";
  9→import { Video, Play, Pause, X, Film } from "lucide-react";
 10→import { AnimatePresence, motion } from "framer-motion";
 11→import { createPortal } from "react-dom";
 12→import { BaseToolRenderer } from "../components";
 13→import { TOOL_ICON_CLS } from "../toolColors";
 14→import { cn } from "@/shared/lib/utils";
 15→import { getBaseURL } from "@/shared/config/api.config";
 16→import * as browserViews from "@/platform/native/browser-views";
 17→import type { ToolRendererProps } from "../../chat-types";
 18→
 19→// ---------------------------------------------------------------------------
 20→// Types
 21→// ---------------------------------------------------------------------------
 22→
 23→interface MappedChapter {
 24→  title: string;
 25→  time: number;
 26→}
 27→
 28→interface MappedEvent {
 29→  type: string;
 30→  time: number;
 31→  text?: string;
 32→  url?: string;
 33→  direction?: string;
 34→}
 35→
 36→// ---------------------------------------------------------------------------
 37→// Helpers
 38→// ---------------------------------------------------------------------------
 39→
 40→function parseResultJson(toolResult?: { content?: unknown }): Record<string, unknown> | null {
 41→  if (!toolResult?.content) return null;
 42→  let text = "";
 43→  if (typeof toolResult.content === "string") {
 44→    text = toolResult.content;
 45→  } else if (Array.isArray(toolResult.content)) {
 46→    const textBlock = toolResult.content.find(
 47→      (b: Record<string, unknown>) => b?.type === "text" && typeof b.text === "string"
 48→    );
 49→    if (textBlock) text = (textBlock as { text: string }).text;
 50→  }
 51→  if (!text) return null;
 52→  try {
 53→    return JSON.parse(text);
 54→  } catch {
 55→    return null;
 56→  }
 57→}
 58→
 59→function formatTime(seconds: number): string {
 60→  const mins = Math.floor(seconds / 60);
 61→  const secs = Math.floor(seconds % 60);
 62→  return `${mins}:${secs.toString().padStart(2, "0")}`;
 63→}
 64→
 65→function formatDuration(seconds: number): string {
 66→  if (seconds < 60) return `${seconds.toFixed(1)}s`;
 67→  const mins = Math.floor(seconds / 60);
 68→  const secs = seconds % 60;
 69→  return `${mins}m ${secs.toFixed(0)}s`;
 70→}
 71→
 72→function useStreamUrl(filePath: string | undefined): string | null {
 73→  const [url, setUrl] = useState<string | null>(null);
 74→  useEffect(() => {
 75→    if (!filePath) return;
 76→    let cancelled = false;
 77→    getBaseURL()
 78→      .then((base) => {
 79→        if (!cancelled) setUrl(`${base}/files/stream?path=${encodeURIComponent(filePath)}`);
 80→      })
 81→      .catch(() => {});
 82→    return () => {
 83→      cancelled = true;
 84→    };
 85→  }, [filePath]);
 86→  return url;
 87→}
 88→
 89→const EVENT_LABELS: Record<string, string> = {
 90→  click: "Click",
 91→  type: "Type",
 92→  scroll: "Scroll",
 93→  navigate: "Navigate",
 94→  drag: "Drag",
 95→};
 96→
 97→function eventLabel(event: MappedEvent): string {
 98→  const base = EVENT_LABELS[event.type] ?? event.type;
 99→  if (event.type === "navigate" && event.url) {
100→    try {
101→      return `Navigate → ${new URL(event.url).hostname}`;
102→    } catch {
103→      return base;
104→    }
105→  }
106→  if (event.type === "type" && event.text) {
107→    const preview = event.text.length > 25 ? event.text.slice(0, 25) + "…" : event.text;
108→    return `Type "${preview}"`;
109→  }
110→  if (event.type === "scroll" && event.direction) {
111→    return `Scroll ${event.direction}`;
112→  }
113→  return base;
114→}
115→
116→// ---------------------------------------------------------------------------
117→// recording_start
118→// ---------------------------------------------------------------------------
119→
120→export function RecordingStartToolRenderer({ toolUse, toolResult, isLoading }: ToolRendererProps) {
121→  const result = parseResultJson(toolResult);
122→  const sessionId = result?.sessionId as string | undefined;
123→
124→  return (
125→    <BaseToolRenderer
126→      toolName="Start Recording"
127→      icon={<Video className={cn(TOOL_ICON_CLS, "text-muted-foreground")} />}
128→      toolUse={toolUse}
129→      toolResult={toolResult}
130→      isLoading={isLoading}
131→      renderSummary={() =>
