138→}
139→
140→// ---------------------------------------------------------------------------
141→// recording_stop
142→// ---------------------------------------------------------------------------
143→
144→export function RecordingStopToolRenderer({ toolUse, toolResult, isLoading }: ToolRendererProps) {
145→  const result = parseResultJson(toolResult);
146→  const outputPath = result?.outputPath as string | undefined;
147→  const thumbnailPath = result?.thumbnailPath as string | undefined;
148→  const duration = result?.duration as number | undefined;
149→  const chapters = (result?.chapters as MappedChapter[] | undefined) ?? [];
150→  const events = (result?.events as MappedEvent[] | undefined) ?? [];
151→  const eventCount = (result?.eventCount as number | undefined) ?? events.length;
152→
153→  const hasVideo = !!outputPath && outputPath.length > 0;
154→  const [modalOpen, setModalOpen] = useState(false);
155→
156→  // Loading / no result
157→  if (isLoading || !toolResult) {
158→    return (
159→      <BaseToolRenderer
160→        toolName="Screen Recording"
161→        icon={<Video className={cn(TOOL_ICON_CLS, "text-primary")} />}
162→        toolUse={toolUse}
163→        toolResult={toolResult}
164→        isLoading={isLoading}
165→      />
166→    );
167→  }
168→
169→  // Error
170→  if (toolResult.is_error) {
171→    return (
172→      <BaseToolRenderer
173→        toolName="Screen Recording"
174→        icon={<Video className={cn(TOOL_ICON_CLS, "text-primary")} />}
175→        toolUse={toolUse}
176→        toolResult={toolResult}
177→        showContentOnError
178→      />
179→    );
180→  }
181→
182→  // No video
183→  if (!hasVideo) {
184→    return (
185→      <BaseToolRenderer
186→        toolName="Screen Recording"
187→        icon={<Video className={cn(TOOL_ICON_CLS, "text-primary")} />}
188→        toolUse={toolUse}
189→        toolResult={toolResult}
190→        renderSummary={() => (
191→          <span className="text-muted-foreground text-xs italic">events-only, no video</span>
192→        )}
193→      />
194→    );
195→  }
196→
197→  // Video available — use BaseToolRenderer as structural host but make the card prominent.
198→  // BaseToolRenderer is required because the parent ToolUseBlock uses CSS containment
199→  // that collapses content rendered outside it.
200→  return (
201→    <BaseToolRenderer
202→      toolName="Screen Recording"
203→      icon={<Film className={cn(TOOL_ICON_CLS, "text-primary")} />}
204→      toolUse={toolUse}
205→      toolResult={toolResult}
206→      defaultExpanded
207→      fullWidthContent
208→      renderSummary={() =>
209→        duration != null ? (
210→          <span className="text-muted-foreground text-sm">{formatDuration(duration)}</span>
211→        ) : null
212→      }
213→    >
214→      <RecordingCard
215→        thumbnailPath={thumbnailPath}
216→        duration={duration}
217→        eventCount={eventCount}
218→        onClick={() => setModalOpen(true)}
219→      />
220→
221→      <AnimatePresence>
222→        {modalOpen && (
223→          <VideoModal
224→            outputPath={outputPath}
225→            thumbnailPath={thumbnailPath}
226→            duration={duration}
227→            chapters={chapters}
228→            events={events}
229→            eventCount={eventCount}
230→            onClose={() => setModalOpen(false)}
231→          />
232→        )}
233→      </AnimatePresence>
234→    </BaseToolRenderer>
235→  );
236→}
