238→// ---------------------------------------------------------------------------
239→// RecordingCard — prominent inline card in chat flow
240→// ---------------------------------------------------------------------------
241→
242→function RecordingCard({
243→  thumbnailPath,
244→  duration,
245→  eventCount,
246→  onClick,
247→}: {
248→  thumbnailPath?: string;
249→  duration?: number;
250→  eventCount: number;
251→  onClick: () => void;
252→}) {
253→  const thumbUrl = useStreamUrl(thumbnailPath);
254→
255→  return (
