328→// ---------------------------------------------------------------------------
329→// VideoModal — overlay player with metadata sidebar
330→// ---------------------------------------------------------------------------
331→
332→function VideoModal({
333→  outputPath,
334→  thumbnailPath,
335→  duration,
336→  chapters,
337→  events,
338→  eventCount,
339→  onClose,
340→}: {
341→  outputPath: string;
342→  thumbnailPath?: string;
343→  duration?: number;
344→  chapters: MappedChapter[];
345→  events: MappedEvent[];
346→  eventCount: number;
347→  onClose: () => void;
348→}) {
349→  const videoUrl = useStreamUrl(outputPath);
350→  const thumbUrl = useStreamUrl(thumbnailPath);
351→  const videoRef = useRef<HTMLVideoElement>(null);
352→  const [playing, setPlaying] = useState(false);
353→  const [currentTime, setCurrentTime] = useState(0);
354→
355→  const totalDuration = duration ?? 0;
356→  const hasChapters = chapters.length > 0;
357→  const meaningfulEvents = events.filter((e) => e.type !== "idle" && e.type !== "screenshot");
358→
359→  // Hide native BrowserViews (they render above web content)
360→  useEffect(() => {
361→    browserViews.hideAll();
362→    return () => {
363→      browserViews.showAll();
364→    };
365→  }, []);
366→
367→  // Auto-play
368→  useEffect(() => {
369→    if (videoRef.current && videoUrl) {
370→      videoRef.current.play().catch(() => {});
371→    }
372→  }, [videoUrl]);
373→
374→  // Escape to close
375→  useEffect(() => {
376→    const handler = (e: KeyboardEvent) => {
377→      if (e.key === "Escape") onClose();
378→    };
379→    window.addEventListener("keydown", handler);
380→    return () => window.removeEventListener("keydown", handler);
381→  }, [onClose]);
382→
383→  const seekTo = useCallback(
384→    (time: number) => {
385→      if (!videoRef.current) return;
386→      videoRef.current.currentTime = time;
387→      if (!playing) videoRef.current.play().catch(() => {});
388→    },
389→    [playing]
390→  );
391→
392→  const handlePlayPause = useCallback(() => {
393→    if (!videoRef.current) return;
394→    if (playing) videoRef.current.pause();
395→    else videoRef.current.play().catch(() => {});
396→  }, [playing]);
397→
398→  return createPortal(
399→    <motion.div
400→      initial={{ opacity: 0 }}
401→      animate={{ opacity: 1 }}
402→      exit={{ opacity: 0 }}
403→      transition={{ duration: 0.2 }}
404→      className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm"
405→      onClick={onClose}
406→    >
407→      <motion.div
408→        initial={{ scale: 0.92, opacity: 0 }}
409→        animate={{ scale: 1, opacity: 1 }}
410→        exit={{ scale: 0.92, opacity: 0 }}
411→        transition={{ duration: 0.25, ease: [0.165, 0.84, 0.44, 1] }}
412→        className="bg-background border-border/40 relative flex max-h-[85vh] w-[90vw] max-w-5xl flex-col overflow-hidden rounded-xl border shadow-2xl"
413→        onClick={(e) => e.stopPropagation()}
414→      >
415→        {/* Close button */}
416→        <button
417→          type="button"
418→          onClick={onClose}
419→          className="absolute top-3 right-3 z-10 flex h-8 w-8 items-center justify-center rounded-full bg-black/40 text-white/80 backdrop-blur-sm transition-colors duration-150 hover:bg-black/60 hover:text-white"
420→          aria-label="Close player"
421→        >
422→          <X className="h-4 w-4" />
423→        </button>
424→
425→        <div className="flex min-h-0 flex-1">
426→          {/* Video panel */}
427→          <div className="flex min-w-0 flex-1 flex-col">
428→            <div
429→              className="relative w-full cursor-pointer bg-black"
430→              style={{ aspectRatio: "16 / 9" }}
431→              onClick={handlePlayPause}
432→            >
433→              {videoUrl && (
434→                <video
435→                  ref={videoRef}
436→                  src={videoUrl}
437→                  poster={thumbUrl ?? undefined}
438→                  className="absolute inset-0 h-full w-full object-contain"
439→                  onEnded={() => setPlaying(false)}
440→                  onPause={() => setPlaying(false)}
441→                  onPlay={() => setPlaying(true)}
442→                  onTimeUpdate={() => {
443→                    if (videoRef.current) setCurrentTime(videoRef.current.currentTime);
444→                  }}
445→                  preload="auto"
446→                />
447→              )}
448→
449→              {/* Play/Pause overlay */}
450→              <div
451→                className={cn(
452→                  "absolute inset-0 flex items-center justify-center transition-opacity duration-200",
453→                  playing ? "opacity-0 hover:opacity-100" : "opacity-100"
454→                )}
455→              >
456→                <div className="flex h-14 w-14 items-center justify-center rounded-full bg-white/20 backdrop-blur-sm">
457→                  {playing ? (
458→                    <Pause className="h-6 w-6 fill-white text-white" />
459→                  ) : (
460→                    <Play className="ml-1 h-6 w-6 fill-white text-white" />
461→                  )}
462→                </div>
463→              </div>
464→
465→              {/* Time */}
466→              {totalDuration > 0 && (
467→                <div className="absolute right-3 bottom-3 rounded bg-black/70 px-2 py-1 text-xs font-medium text-white">
468→                  {formatTime(currentTime)} / {formatTime(totalDuration)}
469→                </div>
470→              )}
471→            </div>
472→
473→            {/* Progress bar */}
474→            {totalDuration > 0 && (
475→              <ProgressBar
476→                duration={totalDuration}
477→                currentTime={currentTime}
478→                chapters={chapters}
479→                onSeek={seekTo}
480→              />
481→            )}
482→          </div>
483→
484→          {/* Metadata sidebar */}
485→          {(meaningfulEvents.length > 0 || hasChapters) && (
486→            <div className="border-border/40 flex w-64 flex-shrink-0 flex-col border-l">
487→              <div className="text-muted-foreground px-3 pt-3 pb-2 text-[11px] font-semibold tracking-wider uppercase">
488→                Timeline
489→              </div>
490→              <div className="chat-scroll-contain flex-1 overflow-y-auto">
491→                {hasChapters
492→                  ? chapters.map((ch, i) => {
493→                      const chapterEvents = meaningfulEvents.filter((e) => {
494→                        const nextChapter = chapters[i + 1];
495→                        return e.time >= ch.time && (!nextChapter || e.time < nextChapter.time);
496→                      });
497→                      return (
498→                        <div key={i} className="border-border/20 border-b last:border-b-0">
499→                          <button
500→                            type="button"
501→                            className="text-foreground hover:bg-muted/40 flex w-full items-baseline gap-2 px-3 py-2 text-left text-xs font-medium transition-colors"
502→                            onClick={() => seekTo(ch.time)}
503→                          >
504→                            <span className="text-muted-foreground flex-shrink-0 font-mono text-[10px]">
505→                              {formatTime(ch.time)}
506→                            </span>
507→                            <span className="truncate">{ch.title}</span>
508→                          </button>
509→                          {chapterEvents.map((evt, j) => (
510→                            <button
511→                              key={j}
512→                              type="button"
513→                              className="text-muted-foreground hover:bg-muted/30 hover:text-foreground flex w-full items-baseline gap-2 px-3 py-1 pl-6 text-left text-[11px] transition-colors"
514→                              onClick={() => seekTo(evt.time)}
515→                            >
516→                              <span className="flex-shrink-0 font-mono text-[10px]">
517→                                {formatTime(evt.time)}
518→                              </span>
519→                              <span className="truncate">{eventLabel(evt)}</span>
520→                            </button>
521→                          ))}
522→                        </div>
523→                      );
524→                    })
525→                  : meaningfulEvents.map((evt, i) => (
526→                      <button
527→                        key={i}
528→                        type="button"
529→                        className="text-muted-foreground hover:bg-muted/30 hover:text-foreground flex w-full items-baseline gap-2 px-3 py-1.5 text-left text-[11px] transition-colors"
530→                        onClick={() => seekTo(evt.time)}
531→                      >
532→                        <span className="flex-shrink-0 font-mono text-[10px]">
533→                          {formatTime(evt.time)}
534→                        </span>
535→                        <span className="truncate">{eventLabel(evt)}</span>
536→                      </button>
537→                    ))}
538→              </div>
539→              <div className="border-border/40 text-muted-foreground flex items-center gap-2 border-t px-3 py-2 text-[11px]">
540→                {eventCount > 0 && <span>{eventCount} events</span>}
541→                {eventCount > 0 && hasChapters && <span>·</span>}
542→                {hasChapters && <span>{chapters.length} chapters</span>}
543→              </div>
544→            </div>
545→          )}
546→        </div>
547→      </motion.div>
548→    </motion.div>,
549→    document.body
550→  );
551→}
552→
553→// ---------------------------------------------------------------------------
554→// ProgressBar
555→// ---------------------------------------------------------------------------
556→
557→function ProgressBar({
558→  duration,
559→  currentTime,
560→  chapters,
561→  onSeek,
562→}: {
563→  duration: number;
564→  currentTime: number;
565→  chapters: MappedChapter[];
566→  onSeek: (time: number) => void;
567→}) {
568→  const barRef = useRef<HTMLDivElement>(null);
569→
570→  const handleClick = (e: React.MouseEvent) => {
571→    if (!barRef.current) return;
572→    const rect = barRef.current.getBoundingClientRect();
573→    const pct = Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width));
574→    onSeek(pct * duration);
575→  };
576→
577→  if (chapters.length === 0) {
578→    const progress = (currentTime / duration) * 100;
579→    return (
580→      <div
581→        ref={barRef}
582→        className="bg-muted/50 group relative h-1.5 cursor-pointer transition-[height] duration-150 hover:h-2.5"
583→        onClick={handleClick}
