+    const gap = buildGapSegment(lastSourceEnd, sourceDurationMs, outputTime, cfg, maxGap);
+    segments.push(gap);
+    outputTime += gap.outputDurationMs;
+  }
+
+  // Compute trim: everything before first action - padding
+  const trimStartMs = Math.max(0, timestamps[0] - cfg.preActionPaddingMs);
+
+  return {
+    segments,
+    outputDurationMs: outputTime,
+    trimStartMs,
+  };
+}
+
+function buildGapSegment(
+  sourceStart: number,
+  sourceEnd: number,
+  outputStart: number,
+  cfg: SpeedRampConfig,
+  maxGap: number
+): PlaybackSegment {
+  const gapSourceDuration = sourceEnd - sourceStart;
+  let playbackRate = 1;
+  let gapOutputDuration = gapSourceDuration;
+
+  if (gapSourceDuration > cfg.minGapToSpeedUp) {
+    const idealRate = gapSourceDuration / cfg.targetGapOutputMs;
+    const minRateForMaxWait = maxGap === Number.POSITIVE_INFINITY ? 0 : gapSourceDuration / maxGap;
+    const effectiveMax = cfg.maxPlaybackRate;
+    playbackRate = Math.min(idealRate, effectiveMax);","path":"packages/screen-studio/src/recorder/render-plan.ts","commit_id":"ba1021abdde7f01dc32e6bcfe7fda0563ef31525","original_commit_id":"ba1021abdde7f01dc32e6bcfe7fda0563ef31525","user":{"login":"zvadaadam","id":26298744,"node_id":"MDQ6VXNlcjI2Mjk4NzQ0","avatar_url":"https://avatars.githubusercontent.com/u/26298744?v=4","gravatar_id":"","url":"https://api.github.com/users/zvadaadam","html_url":"https://github.com/zvadaadam","followers_url":"https://api.github.com/users/zvadaadam/followers","following_url":"https://api.github.com/users/zvadaadam/following{/other_user}","gists_url":"https://api.github.com/users/zvadaadam/gists{/gist_id}","starred_url":"https://api.github.com/users/zvadaadam/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/zvadaadam/subscriptions","organizations_url":"https://api.github.com/users/zvadaadam/orgs","repos_url":"https://api.github.com/users/zvadaadam/repos","events_url":"https://api.github.com/users/zvadaadam/events{/privacy}","received_events_url":"https://api.github.com/users/zvadaadam/received_events","type":"User","user_view_type":"public","site_admin":false},"body":"**Bug: `minRateForMaxWait` computed but never used — `maxGapOutputMs` is a no-op**

Line 211 computes `minRateForMaxWait` (the minimum playback rate needed to keep a gap's output duration under `maxGapOutputMs`), but line 213 ignores it entirely. The `maxGapOutputMs` config option (default: 2000ms) therefore has zero effect on output.

**Fix:** Incorporate the floor rate:
```ts
playbackRate = Math.max(Math.min(idealRate, effectiveMax), minRateForMaxWait);
```

This ensures that no gap segment exceeds `maxGapOutputMs` in the output video.","created_at":"2026-04-01T14:48:22Z","updated_at":"2026-04-01T14:48:22Z","html_url":"https://github.com/zvadaadam/box-ide/pull/224#discussion_r3022609672","pull_request_url":"https://api.github.com/repos/zvadaadam/box-ide/pulls/224","_links":{"self":{"href":"https://api.github.com/repos/zvadaadam/box-ide/pulls/comments/3022609672"},"html":{"href":"https://github.com/zvadaadam/box-ide/pull/224#discussion_r3022609672"},"pull_request":{"href":"https://api.github.com/repos/zvadaadam/box-ide/pulls/224"}},"reactions":{"url":"https://api.github.com/repos/zvadaadam/box-ide/pulls/comments/3022609672/reactions","total_count":0,"+1":0,"-1":0,"laugh":0,"hooray":0,"confused":0,"heart":0,"rocket":0,"eyes":0},"start_line":null,"original_start_line":null,"start_side":null,"line":213,"original_line":213,"side":"RIGHT","author_association":"OWNER","original_position":213,"position":213,"subject_type":"line"}

